checker_dsl:
EXISTS (`method call MC`) {
  AND {
    EXISTS (`string PACKAGE`) {
      EXISTS (`string TYPE`) {
        EXISTS (`integer I`) {
          AND {
            OR {
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Collection"`),
                (`signature of MC is "contains(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Dictionary"`),
                (`signature of MC is "get(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Hashtable"`),
                (`signature of MC is "contains(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "List"`),
                (`signature of MC is "indexOf(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "List"`),
                (`signature of MC is "lastIndexOf(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Map"`),
                (`signature of MC is "get(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Map"`),
                (`signature of MC is "getOrDefault(java.lang.Object,java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Map"`),
                (`signature of MC is "containsKey(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Map"`),
                (`signature of MC is "containsValue(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Stack"`),
                (`signature of MC is "search(java.lang.Object)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Vector"`),
                (`signature of MC is "indexOf(java.lang.Object,int)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util"`),
                (`TYPE is "Vector"`),
                (`signature of MC is "lastIndexOf(java.lang.Object,int)"`),
                (`I is 0`)
              },
              AND {
                (`PACKAGE is "java.util.concurrent"`),
                (`TYPE is "ConcurrentHashMap"`),
                (`signature of MC is "contains(java.lang.Object)"`),
                (`I is 0`)
              }
            },
            (`declaring type DT of MC has a transitive source supertype SST with qualified name PACKAGE.TYPE`),
            (`type of parameter at index I of MC is java.lang.Object`)
          }
        }
      }
    },
    EXISTS (`ref type TYPEARG`) {
      EXISTS (`ref type ARGTYPE`) {
        EXISTS (`integer IDX`) {
          AND {
            (`TYPEARG is the source declaration of the element type of the collection for MC at index IDX`),
            (`ARGTYPE is the type of argument at index IDX of MC, boxed if primitive`),
            NOT {
              (`TYPEARG and ARGTYPE have a type intersection`)
            }
          }
        }
      }
    }
  }
}
